prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org ?orgLabel ?created WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "1ad939eef40c461dafae27f75a0586d3" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  OPTIONAL { ?org rdfs:label ?orgLabel . }
  OPTIONAL { ?model tai:modelCreated ?created . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?originalId ?normalizedId ?created WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(CONTAINS(LCASE(STR(?originalId)), "1ad939eef40c461dafae27f75a0586d3") || 
         CONTAINS(LCASE(STR(?normalizedId)), "1ad939eef40c461dafae27f75a0586d3") ||
         CONTAINS(LCASE(STR(?model)), "1ad939eef40c461dafae27f75a0586d3"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?initPartRef ?loopType WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_628f8db4_6e66_4dbc_bf51_0a06087845fd> .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bboExt:initiatingParticipantRef ?initPartRef . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?participant ?partName WHERE {
  ?participant a bboExt:Participant .
  ?participant tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_628f8db4_6e66_4dbc_bf51_0a06087845fd> .
  OPTIONAL { ?participant bbo:name ?partName . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?event ?eventName ?eventType ?isInterrupting WHERE {
  ?event a ?eventType .
  ?event tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_628f8db4_6e66_4dbc_bf51_0a06087845fd> .
  FILTER(?eventType IN (bboExt:StartEvent, bboExt:EndEvent, bboExt:IntermediateCatchEvent))
  OPTIONAL { ?event bbo:name ?eventName . }
  OPTIONAL { ?event bboExt:isInterrupting ?isInterrupting . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayName ?gatewayType ?direction ?default WHERE {
  ?gateway a ?gatewayType .
  ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_628f8db4_6e66_4dbc_bf51_0a06087845fd> .
  FILTER(?gatewayType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
  OPTIONAL { ?gateway bboExt:default ?default . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?edge ?edgeName ?sourceName ?targetName ?isImmediate WHERE {
  ?edge a bbo:SequenceFlow .
  ?edge tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_628f8db4_6e66_4dbc_bf51_0a06087845fd> .
  OPTIONAL { ?edge bbo:name ?edgeName . }
  OPTIONAL { ?edge bbo:has_sourceRef ?source . ?source bbo:name ?sourceName . }
  OPTIONAL { ?edge bbo:has_targetRef ?target . ?target bbo:name ?targetName . }
  OPTIONAL { ?edge bboExt:isImmediate ?isImmediate . }
}
ORDER BY ?sourceName

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?msgFlow ?sourceRef ?targetRef ?msgRef WHERE {
  ?msgFlow a bboExt:MessageFlow .
  ?msgFlow tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_628f8db4_6e66_4dbc_bf51_0a06087845fd> .
  OPTIONAL { ?msgFlow bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?msgFlow bboExt:targetRef ?targetRef . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?msgRef . }
}
